#include <SPI.h>
#include <Wire.h>
#include <EEPROM.h>

// === Pin Definitions ===
#define VALVE_POS 9   // +Z solenoid PWM
#define VALVE_NEG 10  // -Z solenoid PWM
#define IMU_CS    7
#define LED_FAULT 13

// === FSM States ===
enum State { INIT, ARMED, FIRING, SAFE_HOLD, FAULT };
State fsmState = INIT;

// === PID State ===
float attErr=0, rateErr=0, prevAttErr=0;
float kpAtt=2.0, kpRate=0.8, kiRate=0.05, kdRate=0.01;
float rateIntegral=0, prevRateErr=0;
float attSetpoint=0.0;

// === Sensor Data ===
float rollRate=0, rollAngle=0, tankBar=0;
float dvBudget=500.0; // ms of total valve open time remaining

// === Fault/Log ===
int eepromAddr=0;
void logEvent(uint8_t code){
  if(eepromAddr+5 < 1024){
    EEPROM.put(eepromAddr, (uint32_t)millis());
    EEPROM.write(eepromAddr+4, code);
    eepromAddr+=5;
  }
}

// === ICM-42688-P: read gyro Z rate (simplified SPI) ===
float readIMU_RollRate(){
  // Register 0x25 = GYRO_DATA_X1 (high byte)
  digitalWrite(IMU_CS, LOW);
  SPI.transfer(0x25 | 0x80); // read
  int16_t raw = (int16_t)((SPI.transfer(0)<<8) | SPI.transfer(0));
  digitalWrite(IMU_CS, HIGH);
  return raw / 16.4f; // ±2000 dps range
}

// === MPRLS pressure (I2C) ===
float readPressureBar(){
  Wire.beginTransmission(0x18);
  Wire.write(0xAA); Wire.write(0); Wire.write(0);
  Wire.endTransmission();
  delay(5);
  Wire.requestFrom(0x18, 4);
  uint32_t raw=0;
  Wire.read(); // status
  raw  = (uint32_t)Wire.read()<<16;
  raw |= (uint32_t)Wire.read()<<8;
  raw |=  Wire.read();
  // Convert: P_psi = (raw-1677722)*25.0/(15099494-1677722)
  float psi = (raw - 1677722UL) * 25.0f / 13421772.0f;
  return psi * 0.0689476f;
}

// === INA219 valve current (I2C addr 0x40) ===
float readValveCurrent_mA(){
  Wire.beginTransmission(0x40);
  Wire.write(0x04); Wire.endTransmission(false);
  Wire.requestFrom(0x40,2);
  int16_t raw=(Wire.read()<<8)|Wire.read();
  return raw * 0.1f; // 100 uA/LSB default
}

// === Valve fire: pulse width clamped, budget tracked ===
void fireValve(int pin, float pw_ms){
  pw_ms = constrain(pw_ms, 5.0f, 50.0f);
  if(dvBudget < pw_ms){ fsmState=FAULT; logEvent(0xF2); return; }
  digitalWrite(pin, HIGH);
  delay((int)pw_ms);
  digitalWrite(pin, LOW);
  dvBudget -= pw_ms;
}

// === Integrate rate→angle (simple Euler) ===
void updateAngle(float dt){
  rollAngle += rollRate * dt;
}

void setup(){
  Serial.begin(115200);
  SPI.begin();
  Wire.begin();
  pinMode(VALVE_POS, OUTPUT);
  pinMode(VALVE_NEG, OUTPUT);
  pinMode(IMU_CS, OUTPUT);
  pinMode(LED_FAULT, OUTPUT);
  digitalWrite(VALVE_POS, LOW);
  digitalWrite(VALVE_NEG, LOW);
  // IMU: configure ±2000 dps, 1kHz ODR
  digitalWrite(IMU_CS, LOW);
  SPI.transfer(0x4F); SPI.transfer(0x0F); // GYRO_CONFIG0
  digitalWrite(IMU_CS, HIGH);
  logEvent(0x01); // INIT
  fsmState = ARMED;
  Serial.println("{\"event\":\"ARMED\"}");
}

unsigned long lastMs=0, lastAttMs=0;
void loop(){
  unsigned long now = millis();
  wdt_reset(); // hardware watchdog (AVR)

  // --- Sensor reads ---
  rollRate  = readIMU_RollRate();
  tankBar   = readPressureBar();
  float iVal= readValveCurrent_mA();

  // --- FDI checks ---
  if(tankBar > 7.0f){ fsmState=FAULT; logEvent(0xF0); } // over-pressure FS>=2 on 6bar limit
  if(tankBar < 1.5f && fsmState==ARMED){ fsmState=SAFE_HOLD; logEvent(0xF1); }
  // valve stuck: current expected only during FIRING
  if(fsmState!=FIRING && iVal>50.0f){ fsmState=FAULT; logEvent(0xF3); }

  // --- FSM ---
  if(fsmState==FAULT){
    digitalWrite(VALVE_POS,LOW); digitalWrite(VALVE_NEG,LOW);
    digitalWrite(LED_FAULT,HIGH);
    Serial.println("{\"state\":\"FAULT\"}");
    delay(1000); return;
  }
  if(fsmState==SAFE_HOLD){
    digitalWrite(VALVE_POS,LOW); digitalWrite(VALVE_NEG,LOW);
    Serial.println("{\"state\":\"SAFE_HOLD\"}");
    delay(100); return;
  }

  // --- Rate loop (500 Hz) ---
  float dt = (now - lastMs) / 1000.0f;
  if(dt >= 0.002f){
    lastMs = now;
    updateAngle(dt);
    // Attitude loop (50 Hz)
    if(now - lastAttMs >= 20){
      lastAttMs = now;
      attErr = attSetpoint - rollAngle;
      float rateSetpoint = kpAtt * attErr;
      rateErr = rateSetpoint - rollRate;
      rateIntegral += rateErr * 0.02f;
      rateIntegral = constrain(rateIntegral,-10,10);
      float dRateErr = (rateErr - prevRateErr)/0.02f;
      float pw = kpRate*rateErr + kiRate*rateIntegral + kdRate*dRateErr;
      prevRateErr = rateErr;
      prevAttErr  = attErr;
      if(abs(pw) > 2.0f && fsmState==ARMED){
        fsmState = FIRING;
        if(pw > 0) fireValve(VALVE_POS, abs(pw)*10.0f);
        else       fireValve(VALVE_NEG, abs(pw)*10.0f);
        fsmState = ARMED;
      }
    }
    // 1 Hz heartbeat
    static unsigned long hbMs=0;
    if(now-hbMs>=1000){
      hbMs=now;
      Serial.print("{\"roll\":"); Serial.print(rollAngle,2);
      Serial.print(",\"rate\":"); Serial.print(rollRate,2);
      Serial.print(",\"pBar\":"); Serial.print(tankBar,2);
      Serial.print(",\"dv\":"); Serial.print(dvBudget,1);
      Serial.println("}");
    }
  }
}
